import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { onboardAPI } from '../services/api';
import {
  PageHeader, Card, Table, Btn, Modal, Input, Textarea, Badge, Tabs, toast,
} from '../components/ui';
import { CheckCircle2, Circle, UserMinus } from 'lucide-react';

export default function Onboarding() {
  const { hasRole } = useAuth();
  const [tab, setTab] = useState('onboarding');
  const [myRecord, setMyRecord] = useState(null);
  const [allRecords, setAllRecords] = useState([]);
  const [offRecords, setOffRecords] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showInitOff, setShowInitOff] = useState(false);
  const [offForm, setOffForm] = useState({ employee_id: '', reason: '', last_working_date: '' });
  const [submitting, setSubmitting] = useState(false);

  const isPrivileged = hasRole('admin', 'hr');

  const tabs = [
    { key: 'onboarding', label: 'Onboarding' },
    { key: 'offboarding', label: 'Offboarding' },
  ];

  const loadData = async () => {
    setLoading(true);
    try {
      // Load own onboarding
      try {
        const { data } = await onboardAPI.myRecord();
        setMyRecord(data);
      } catch {
        setMyRecord(null);
      }
      // HR: all records
      if (isPrivileged) {
        try {
          const { data } = await onboardAPI.allRecords();
          setAllRecords(data);
        } catch { setAllRecords([]); }

        try {
          const { data } = await onboardAPI.offAll();
          setOffRecords(data);
        } catch { setOffRecords([]); }
      }
    } catch (e) {
      toast('Failed to load onboarding data', 'error');
    } finally {
      setLoading(false);
    }
  };

  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => { loadData(); }, []);

  const handleCompleteTask = async (taskId) => {
    try {
      await onboardAPI.completeTask(taskId);
      toast('Task completed!', 'success');
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to complete task', 'error');
    }
  };



  const handleInitiateOff = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    try {
      await onboardAPI.offInitiate({
        employee_id: parseInt(offForm.employee_id),
        reason: offForm.reason,
        last_working_date: offForm.last_working_date,
      });
      toast('Offboarding initiated', 'success');
      setShowInitOff(false);
      setOffForm({ employee_id: '', reason: '', last_working_date: '' });
      loadData();
    } catch (e) {
      toast(e.response?.data?.detail || 'Failed to initiate offboarding', 'error');
    } finally {
      setSubmitting(false);
    }
  };

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', padding: 80 }}>
        <Spinner size={32} />
      </div>
    );
  }

  const completedTasks = myRecord?.tasks?.filter((t) => t.is_completed)?.length || 0;
  const totalTasks = myRecord?.tasks?.length || 0;
  const progress = totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0;

  return (
    <>
      <PageHeader
        title="Onboarding & Offboarding"
        subtitle="Track employee onboarding tasks and offboarding processes"
        actions={
          isPrivileged && (
            <Btn onClick={() => setShowInitOff(true)}>
              <UserMinus size={16} /> Initiate Offboarding
            </Btn>
          )
        }
      />

      <Tabs tabs={tabs} active={tab} onChange={setTab} />

      {/* Onboarding Tab */}
      {tab === 'onboarding' && (
        <>
          {/* My onboarding checklist */}
          {myRecord && (
            <Card style={{ marginBottom: 24 }}>
              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 16 }}>
                <div>
                  <h3 style={{ fontSize: 16, marginBottom: 4 }}>My Onboarding Progress</h3>
                  <span style={{ color: 'var(--text-muted)', fontSize: 13 }}>
                    {completedTasks} of {totalTasks} tasks completed
                  </span>
                </div>
                <div
                  style={{
                    fontSize: 20,
                    fontWeight: 700,
                    color: progress === 100 ? 'var(--success)' : 'var(--primary)',
                  }}
                >
                  {progress}%
                </div>
              </div>

              {/* Progress bar */}
              <div
                style={{
                  height: 8,
                  background: 'var(--border-light)',
                  borderRadius: 4,
                  overflow: 'hidden',
                  marginBottom: 20,
                }}
              >
                <div
                  style={{
                    height: '100%',
                    width: `${progress}%`,
                    background: progress === 100
                      ? 'var(--success)'
                      : 'linear-gradient(90deg, #0052CC, #0065FF)',
                    borderRadius: 4,
                    transition: 'width 0.4s ease',
                  }}
                />
              </div>

              {/* Task list */}
              <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                {myRecord.tasks?.map((task) => (
                  <div
                    key={task.id}
                    style={{
                      display: 'flex',
                      alignItems: 'center',
                      gap: 12,
                      padding: '12px 16px',
                      background: task.is_completed ? 'var(--success-light)' : 'var(--surface-2)',
                      borderRadius: 'var(--radius)',
                      border: `1px solid ${task.is_completed ? 'var(--success-border)' : 'var(--border-light)'}`,
                    }}
                  >
                    {task.is_completed ? (
                      <CheckCircle2 size={20} color="var(--success)" />
                    ) : (
                      <button
                        onClick={() => handleCompleteTask(task.id)}
                        style={{
                          background: 'none',
                          border: 'none',
                          cursor: 'pointer',
                          padding: 0,
                          color: 'var(--text-muted)',
                        }}
                      >
                        <Circle size={20} />
                      </button>
                    )}
                    <div style={{ flex: 1 }}>
                      <div
                        style={{
                          fontSize: 14,
                          fontWeight: 500,
                          textDecoration: task.is_completed ? 'line-through' : 'none',
                          color: task.is_completed ? 'var(--text-muted)' : 'var(--text-primary)',
                        }}
                      >
                        {task.title}
                      </div>
                      {task.description && (
                        <div style={{ fontSize: 12, color: 'var(--text-muted)', marginTop: 2 }}>
                          {task.description}
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </Card>
          )}

          {/* HR view: all onboarding records */}
          {isPrivileged && allRecords.length > 0 && (
            <Card style={{ padding: 0, overflow: 'hidden' }}>
              <div style={{ padding: '16px 20px', borderBottom: '1px solid var(--border)' }}>
                <h3 style={{ fontSize: 16 }}>All Onboarding Records</h3>
              </div>
              <Table
                cols={[
                  { key: 'employee_id', label: 'Emp ID' },
                  { key: 'status', label: 'Status', render: (r) => (
                    <Badge variant={r.status === 'completed' ? 'success' : 'info'}>
                      {r.status}
                    </Badge>
                  )},
                  { key: 'tasks', label: 'Progress', render: (r) => {
                    const done = r.tasks?.filter((t) => t.is_completed)?.length || 0;
                    const total = r.tasks?.length || 0;
                    return `${done}/${total}`;
                  }},
                  { key: 'created_at', label: 'Started', render: (r) =>
                    r.created_at ? new Date(r.created_at).toLocaleDateString() : 'â€”'
                  },
                ]}
                rows={allRecords}
                loading={false}
              />
            </Card>
          )}
        </>
      )}

      {/* Offboarding Tab */}
      {tab === 'offboarding' && (
        <Card style={{ padding: 0, overflow: 'hidden' }}>
          <Table
            cols={[
              { key: 'employee_id', label: 'Emp ID' },
              { key: 'reason', label: 'Reason', render: (r) => r.reason || 'â€”' },
              { key: 'last_working_date', label: 'Last Day' },
              { key: 'clearance_status', label: 'Clearance', render: (r) => (
                <Badge variant={
                  r.clearance_status === 'cleared' ? 'success'
                  : r.clearance_status === 'hold' ? 'danger'
                  : 'warning'
                }>
                  {r.clearance_status || 'pending'}
                </Badge>
              )},
              { key: 'tasks', label: 'Tasks', render: (r) => {
                const done = r.tasks?.filter((t) => t.is_completed)?.length || 0;
                const total = r.tasks?.length || 0;
                return `${done}/${total}`;
              }},
            ]}
            rows={offRecords}
            loading={false}
            emptyMsg="No offboarding records"
          />
        </Card>
      )}

      {/* Initiate Offboarding Modal */}
      <Modal
        open={showInitOff}
        onClose={() => setShowInitOff(false)}
        title="Initiate Offboarding"
        width={440}
      >
        <form onSubmit={handleInitiateOff}>
          <Input
            label="Employee ID"
            type="number"
            value={offForm.employee_id}
            onChange={(e) => setOffForm({ ...offForm, employee_id: e.target.value })}
            required
            id="off-emp-id"
          />
          <Textarea
            label="Reason"
            value={offForm.reason}
            onChange={(e) => setOffForm({ ...offForm, reason: e.target.value })}
            placeholder="Reason for offboarding"
            required
            id="off-reason"
          />
          <Input
            label="Last Working Date"
            type="date"
            value={offForm.last_working_date}
            onChange={(e) => setOffForm({ ...offForm, last_working_date: e.target.value })}
            required
            id="off-last-date"
          />
          <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10, marginTop: 8 }}>
            <Btn variant="secondary" onClick={() => setShowInitOff(false)}>Cancel</Btn>
            <Btn type="submit" loading={submitting}>Initiate</Btn>
          </div>
        </form>
      </Modal>
    </>
  );
}
